function test_urlencode() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    // todo: add nulls
    // todo: add sort
    $dict1 = array(
        'a' => 1,
        'c' => '+&',
    );
    // as key-order not preserved, expect mixed order
    $expected1 = 'a=1&c=%2B%26';
    $expected2 = 'c=%2B%26&a=1';
    $encoded = $exchange->urlencode($dict1);
    assert($encoded === $expected1 || $encoded === $expected2, 'testUrlencode: expected ' . $expected1 . ' or ' . $expected2 . ' but got ' . $encoded);
}
